import sys
sys.setrecursionlimit(10000)

def find_bridges(n, adj):
    """
    adj: dict {u: [v, ...]} undirected
    Returns list of bridges as sorted (u,v) tuples with u < v.
    """
    disc  = [-1] * n
    low   = [0]  * n
    timer = [0]
    bridges = []

    def dfs(u, parent):
        disc[u] = low[u] = timer[0]
        timer[0] += 1
        for v in adj.get(u, []):
            if disc[v] == -1:
                dfs(v, u)
                low[u] = min(low[u], low[v])
                if ___________:          # bridge condition
                    bridges.append((min(u,v), max(u,v)))
            elif v != parent:
                low[u] = min(low[u], disc[v])

    for u in range(n):
        if disc[u] == -1:
            dfs(u, -1)
    return sorted(bridges)
